import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface FileTypeBreakdown {
  type: string;
  value: number;
}

interface StorageData {
  totalSpace: string;
  usedSpace: string;
  freeSpace: string;
  fileTypeBreakdown: FileTypeBreakdown[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const storageData = response.data as StorageData;
  const metaData = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Storage Usage
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: metaData.primaryColor }}>
              {storageData.usedSpace} / {storageData.totalSpace}
            </Typography>
            <Typography variant="caption" sx={{ color: metaData.accentColor }}>
              Free Space: {storageData.freeSpace}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <PieChart
              series={[
                {
                  data: storageData.fileTypeBreakdown.map((item) => ({
                    id: item.type,
                    value: item.value,
                    label: item.type,
                  })),
                  innerRadius: 0.5,
                  outerRadius: 1,
                  color: metaData.primaryColor,
                },
              ]}
              sx={{
                '& .MuiChartsPieLabel-root': {
                  fontSize: 10,
                  fill: '#6B7280',
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
